"""# **AQ5. One vs Rest**

Given the train and test dataset, predict the classes of observations of test data (Xtest) using the One-vs-Rest strategy in Logistic regression.
"""

#import logistic regression
from sklearn.linear_model import LogisticRegression

def predictions(Xtrain, ytrain, Xtest):
    # define model with One-vs-All strategy
    model = LogisticRegression(multi_class='ovr')

    # train the model
    model.fit(Xtrain, ytrain)

    # make predictions
    predictions = model.predict(Xtest)

    return predictions

